/** Parser for Assignment 2 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }
  
  Parser(Reader inputStream) { this(new Lexer(inputStream)); }
  
  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }
  
  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp) */
  public AST parse() throws ParseException {
    AST ast = parseExp();
    Token extra = in.readToken();
    if (extra != null) {
      throw new ParseException("Unexpected token after expression: " + extra);
    }
    return ast;
  }

  /** Parses:
    *   <exp> :: = if <exp> then <exp> else <exp>
    *            | let <prop-def-list> in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token token = in.peek();
    if (token == Lexer.IF) {
      return parseIf();
    }
    if (token == Lexer.LET) {
      return parseLet();
    }
    if (token == Lexer.MAP) {
      return parseMap();
    }

    AST left = parseTerm();
    while (isBinOp(in.peek())) {
      BinOp op = ((OpToken) in.readToken()).toBinOp();
      AST right = parseTerm();
      left = new BinOpApp(op, left, right);
    }
    return left;
  }

  /* Many more parse methods follow.  I suggest defining separate parse methods for parsing
     Term, If, Map, and Let as shown in the syntax diagrams.  You will need additional
     methods for select contructions.  Let the syntax diagrams and your personal program
     design taste be your guide.  Avoid repeating code patterns. */

  /** Parses:
    *   <term> ::= <unop> <term>
    *            | <factor> { ( <exp-list> ) }
    *            | <empty>
    *            | <int>
    *            | <bool>
    */
  private AST parseTerm() {
    Token token = in.peek();

    if (isUnOp(token)) {
      UnOp op = ((OpToken) in.readToken()).toUnOp();
      return new UnOpApp(op, parseTerm());
    }

    if (token instanceof Constant) {
      in.readToken();
      return (AST) token;
    }

    AST result = parseFactor();
    while (in.peek() == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      expect(RightParen.ONLY);
      result = new App(result, args);
    }
    return result;
  }

  /** Parses:
    *   <factor> ::= ( <exp> ) | <prim> | <id>
    */
  private AST parseFactor() {
    Token token = in.peek();
    if (token == LeftParen.ONLY) {
      in.readToken();
      AST exp = parseExp();
      expect(RightParen.ONLY);
      return exp;
    }
    if (token instanceof PrimFun || token instanceof Variable) {
      in.readToken();
      return (AST) token;
    }
    throw new ParseException("Expected factor, found: " + tokenToString(token));
  }

  /** Parses:
    *   <exp-list> ::= { <prop-exp-list> }
    *   <prop-exp-list> ::= <exp> { , <exp> }*
    */
  private AST[] parseExpList() {
    if (in.peek() == RightParen.ONLY) {
      return new AST[0];
    }

    ArrayList<AST> exps = new ArrayList<AST>();
    exps.add(parseExp());
    while (in.peek() == Comma.ONLY) {
      in.readToken();
      exps.add(parseExp());
    }
    return exps.toArray(new AST[exps.size()]);
  }

  /** Parses:
    *   if <exp> then <exp> else <exp>
    */
  private AST parseIf() {
    expect(Lexer.IF);
    AST test = parseExp();
    expect(Lexer.THEN);
    AST conseq = parseExp();
    expect(Lexer.ELSE);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses:
    *   let <def>+ in <exp>
    *   <def> ::= <id> := <exp> ;
    */
  private AST parseLet() {
    expect(Lexer.LET);
    ArrayList<Def> defs = new ArrayList<Def>();
    defs.add(parseDef());
    while (in.peek() instanceof Variable) {
      defs.add(parseDef());
    }
    expect(Lexer.IN);
    AST body = parseExp();
    return new Let(defs.toArray(new Def[defs.size()]), body);
  }

  /** Parses:
    *   map <id-list> to <exp>
    *   <id-list> ::= { <prop-id-list> }
    *   <prop-id-list> ::= <id> { , <id> }*
    */
  private AST parseMap() {
    expect(Lexer.MAP);
    Variable[] vars = parseIdList();
    expect(Lexer.TO);
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses one definition: <id> := <exp> ; */
  private Def parseDef() {
    Variable lhs = parseVariable();
    expect(Lexer.BIND);
    AST rhs = parseExp();
    expect(SemiColon.ONLY);
    return new Def(lhs, rhs);
  }

  /** Parses an optional comma-separated id list. */
  private Variable[] parseIdList() {
    ArrayList<Variable> ids = new ArrayList<Variable>();
    if (in.peek() == Lexer.TO) {
      return new Variable[0];
    }

    ids.add(parseVariable());
    while (in.peek() == Comma.ONLY) {
      in.readToken();
      ids.add(parseVariable());
    }
    return ids.toArray(new Variable[ids.size()]);
  }

  /** Reads and returns a variable token. */
  private Variable parseVariable() {
    Token token = in.readToken();
    if (token instanceof Variable) {
      return (Variable) token;
    }
    throw new ParseException("Expected variable, found: " + tokenToString(token));
  }

  /** Reads and checks that next token is expectedToken. */
  private void expect(Token expectedToken) {
    Token actual = in.readToken();
    if (actual != expectedToken) {
      throw new ParseException(
        "Expected token " + expectedToken + " but found " + tokenToString(actual)
      );
    }
  }

  private boolean isUnOp(Token token) {
    return token instanceof OpToken && ((OpToken) token).isUnOp();
  }

  private boolean isBinOp(Token token) {
    return token instanceof OpToken && ((OpToken) token).isBinOp();
  }

  private String tokenToString(Token token) {
    if (token == null) return "end of input";
    return token.toString();
  }
}
